int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int h, w;
    cin >> h >> w;
    vector<string> g(h);
    for (string& row : g) cin >> row;
    int dr[4] = {1, -1, 0, 0};
    int dc[4] = {0, 0, 1, -1};
    int ans = 0;
    for (int sr = 0; sr < h; ++sr) {
        for (int sc = 0; sc < w; ++sc) {
            if (g[sr][sc] == '#') continue;
            vector<vector<int>> dist(h, vector<int>(w, -1));
            queue<pair<int, int>> q;
            dist[sr][sc] = 0;
            q.push({sr, sc});
            while (!q.empty()) {
                auto [r, c] = q.front();
                q.pop();
                ans = max(ans, dist[r][c]);
                for (int d = 0; d < 4; ++d) {
                    int nr = r + dr[d], nc = c + dc[d];
                    if (nr < 0 || nr >= h || nc < 0 || nc >= w || g[nr][nc] == '#') continue;
                    if (dist[nr][nc] != -1) continue;
                    dist[nr][nc] = dist[r][c] + 1;
                    q.push({nr, nc});
                }
            }
        }
    }
    cout << ans << '\n';
    return 0;
}

