long long choose2(long long x) { return x * (x - 1) / 2; }

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;
    vector<int> a(n);
    map<int, long long> cnt;
    for (int& x : a) {
        cin >> x;
        cnt[x]++;
    }
    long long total = 0;
    for (const auto& kv : cnt) total += choose2(kv.second);
    for (int x : a) {
        long long c = cnt[x];
        cout << total - choose2(c) + choose2(c - 1) << '\n';
    }
    return 0;
}

