#include <vector>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n, x, y;
    cin >> n >> x >> y;
    --x; --y;
    vector<vector<int>> graph(n);
    for (int i = 0; i + 1 < n; ++i) {
        graph[i].push_back(i + 1);
        graph[i + 1].push_back(i);
    }
    graph[x].push_back(y);
    graph[y].push_back(x);
    vector<long long> ans(n, 0);
    for (int s = 0; s < n; ++s) {
        vector<int> dist(n, -1);
        queue<int> q;
        dist[s] = 0;
        q.push(s);
        while (!q.empty()) {
            int v = q.front();
            q.pop();
            for (int to : graph[v]) {
                if (dist[to] != -1) continue;
                dist[to] = dist[v] + 1;
                q.push(to);
            }
        }
        for (int t = s + 1; t < n; ++t) ans[dist[t]]++;
    }
    for (int d = 1; d < n; ++d) cout << ans[d] << '\n';
    return 0;
}

