long long fifth(long long x) {
    return x * x * x * x * x;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    long long x;
    cin >> x;
    vector<long long> aOrder, bOrder;
    aOrder.push_back(0);
    for (long long v = 1; v <= 1000; ++v) {
        aOrder.push_back(v);
        aOrder.push_back(-v);
    }
    for (long long v = 1; v <= 1000; ++v) {
        bOrder.push_back(-v);
        bOrder.push_back(v - 1);
    }
    for (long long b : bOrder) {
        for (long long a : aOrder) {
            if (fifth(a) - fifth(b) == x) {
                cout << a << ' ' << b << '\n';
                return 0;
            }
        }
    }
    return 0;
}

