int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n, m, x;
    cin >> n >> m >> x;
    vector<int> cost(n);
    vector<vector<int>> skill(n, vector<int>(m));
    for (int i = 0; i < n; ++i) {
        cin >> cost[i];
        for (int j = 0; j < m; ++j) cin >> skill[i][j];
    }
    int ans = numeric_limits<int>::max();
    for (int mask = 0; mask < (1 << n); ++mask) {
        vector<int> sum(m, 0);
        int total = 0;
        for (int i = 0; i < n; ++i) {
            if (!(mask >> i & 1)) continue;
            total += cost[i];
            for (int j = 0; j < m; ++j) sum[j] += skill[i][j];
        }
        bool ok = true;
        for (int j = 0; j < m; ++j) if (sum[j] < x) ok = false;
        if (ok) ans = min(ans, total);
    }
    cout << (ans == numeric_limits<int>::max() ? -1 : ans) << '\n';
    return 0;
}

