long long parseCents(const string& s) {
    long long integer = 0;
    int i = 0;
    while (i < (int)s.size() && s[i] != '.') {
        integer = integer * 10 + (s[i] - '0');
        ++i;
    }
    long long frac = 0;
    int digits = 0;
    if (i < (int)s.size() && s[i] == '.') ++i;
    while (i < (int)s.size() && digits < 2) {
        frac = frac * 10 + (s[i] - '0');
        ++i;
        ++digits;
    }
    while (digits < 2) {
        frac *= 10;
        ++digits;
    }
    return integer * 100 + frac;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    long long a;
    string b;
    cin >> a >> b;
    cout << a * parseCents(b) / 100 << '\n';
    return 0;
}

